import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';// ✅ REPLACE WITH:
import { adminGetAllUsers, adminDeleteTargetUser } from '../utils/api';

function AdminPanel({ user }) {
  const [users, setUsers] = useState([]);
  const [selectedUser, setSelectedUser] = useState(null);
  const navigate = useNavigate();

  // FIX: Perform security authentication validation access matrix paths early
  useEffect(() => {
    if (!user || user.role !== "admin") {
      navigate("/login");
    } else {
      getAllUsers()
        .then(data => setUsers(data))
        .catch(err => console.error(err));
    }
  }, [user, navigate]);

  if (!user || user.role !== "admin") {
    return null; 
  }

  function viewUserDetails(userId) {
    getUserData(userId).then(data => setSelectedUser(data));
  }

  return (
    <div style={{ padding: "20px" }}>
      <h2>Admin Panel Workspace Area</h2>
      <p>Active user session authentication tag: {user.username}</p>

      <table>
        <thead>
          <tr>
            <th>ID</th><th>Name</th><th>Email</th><th>Actions</th>
          </tr>
        </thead>
        <tbody>
          {users.map(u => (
            <tr key={u.id}>
              <td>{u.id}</td>
              <td>{u.name}</td>
              <td>{u.email}</td>
              <td>
                <button onClick={() => viewUserDetails(u.id)}>View Details Safely</button>
              </td>
            </tr>
          ))}
        </tbody>
      </table>

      {selectedUser && (
        <div style={{ marginTop: "20px", border: "1px solid #ccc", padding: "10px" }}>
          <h3>User Inspector Profiles</h3>
          <p>Name: {selectedUser.name}</p>
          <p>Email: {selectedUser.email}</p>
          <p>Account Security Tier Category Status: {selectedUser.role}</p>
          {/* FIX: Removed raw text password exposure fields */}
        </div>
      )}
    </div>
  );
}

export default AdminPanel;
